import { AppBar, Avatar, Badge, Button, Divider, Drawer, IconButton, List, ListItem, ListItemIcon, ListItemText, makeStyles, Toolbar, Typography } from '@material-ui/core'
import { AddCircle, Dashboard, ExpandMore, PlaylistAddCheck, Mail, Inbox, Settings } from '@material-ui/icons';
import urslogo from '../images/urslogo.png'
import phil from '../images/phil.png'
import React from 'react';
import clsx from 'clsx';
import { withStyles } from '@material-ui/styles';

const StyledBadge = withStyles((theme) => ({
    badge: {
        backgroundColor: '#44b700',
        color: '#44b700',
        boxShadow: `0 0 0 2px ${theme.palette.background.paper}`,
        '&::after': {
            position: 'absolute',
            top: 0,
            left: 0,
            width: '100%',
            height: '100%',
            borderRadius: '50%',
            animation: '$ripple 1.2s infinite ease-in-out',
            border: '1px solid currentColor',
            content: '""',
        },
    },
    '@keyframes ripple': {
        '0%': {
            transform: 'scale(.8)',
            opacity: 1,
        },
        '100%': {
            transform: 'scale(2.4)',
            opacity: 0,
        },
    },
}))(Badge);

const drawerWidth = 60;

const useStyle = makeStyles(theme => {
    return {
        root: {
            display: 'flex',
            '& .MuiToolbar-root': {
                boxShadow: 'rgb(35 68 101 / 5%) 0px 4px 16px, rgb(35 68 101 / 5%) 0px 4px 4px;'
            },
            '& .MuiCard-root': {
                boxShadow: 'rgb(35 68 101 / 5%) 0px 4px 16px, rgb(35 68 101 / 5%) 0px 4px 4px;',

                '&:hover': {
                    transform: 'rotate(2.5deg)',
                    transition: '0.2s'
                }
            }
        },
        page: {
            background: '#f9fbfd',
            width: '100%',
            padding: theme.spacing(3)
        },
        sidebar: {
            width: drawerWidth
        },
        logoContainer: {
            maxWidth: '40px',
            margin: '2px auto'
        },
        logo: {
            width: '100%',
            paddingTop: '10%'
        },
        appbar: {
            width: `calc(100% - ${drawerWidth}px)`
        },
        toolbar: theme.mixins.toolbar,
        title: {
            flexGrow: 1
        },
        lists: {
            marginTop: '10px'
        }
    }
});


export default function Layout({ children }) {
    const classes = useStyle()
    const [state, setState] = React.useState({
        left: false
    });

    const toggleDrawer = (anchor, open) => (event) => {
        if (event.type === 'keydown' && (event.key === 'Tab' || event.key === 'Shift')) {
            return;
        }

        setState({ ...state, [anchor]: open });
    };

    const list = (anchor) => (
        <div
            className={clsx(classes.list)}
            role="presentation"
            onClick={toggleDrawer(anchor, false)}
            onKeyDown={toggleDrawer(anchor, false)}
        >
            <List>
                {['Home', 'Subjects', 'Join'].map((text, index) => (
                    <ListItem button key={text}>
                        <ListItemIcon>{index % 2 === 0 ? <Inbox /> : <Mail />}</ListItemIcon>
                        <ListItemText primary={text} />
                    </ListItem>
                ))}
            </List>
            <Divider />
            <List>
                    <ListItem>
                        <ListItemIcon><Settings /></ListItemIcon>
                        <ListItemText primary='Settings' />
                    </ListItem>
            </List>
        </div>
    );

    const sideLinks = [
        {
            text: 'Dashboard',
            icon: <Dashboard color='error' />,
            path: '/studentDashboard'
        },
        {
            text: 'Subjects',
            icon: <PlaylistAddCheck color='error' />,
            path: '/studentDashboard'
        },
        {
            text: 'Join a Class',
            icon: <AddCircle color='error' />,
            path: '/studentDashboard'
        },
    ]

    return (
        <div className={classes.root}>
            {/* // appbar */}

            <AppBar className={classes.appbar} color='inherit' elevation={0}>
                <Toolbar>
                    <Typography className={classes.title} variant='h5'>
                        Student
                    </Typography>
                    <IconButton>
                        <StyledBadge
                            overlap="circular"
                            anchorOrigin={{
                                vertical: 'bottom',
                                horizontal: 'right',
                            }}
                            variant="dot"
                        >
                            <Avatar src={phil} />
                        </StyledBadge>
                    </IconButton>
                    <Typography variant='caption'>
                        Cris Philip V. Cajurao
                        <IconButton>
                            <ExpandMore />
                        </IconButton>
                    </Typography>
                </Toolbar>
            </AppBar>

            {/* // sidebar */}
            <div>
                {['left', 'right', 'top', 'bottom'].map((anchor) => (
                    <React.Fragment key={anchor}>
                        <Button onClick={toggleDrawer(left, true)}>{left}</Button>
                        <Drawer anchor={left} open={state[left]} onClose={toggleDrawer(left, false)}>
                            {list(left)}
                        </Drawer>
                    </React.Fragment>
                ))}
            </div>


            <div className={classes.page}>
                <div className={classes.toolbar} elevation={0}></div>
                {children}
            </div>
        </div>
    )
}
